    /// Shows an editor dropdown, guarding against the .NET 9 breaking change
    /// where passing null to DropDownControl throws ArgumentNullException.
    /// </summary>
    public void ShowEditorDropDown(IWindowsFormsEditorService editorService, Control control)
    {
        // .NET 9 breaking change: DropDownControl no longer accepts null.
        if (control is not null)
        {
            editorService.DropDownControl(control);
        }
    }

    // .NET 9 breaking change: prefer LibraryImport (source-generated P/Invoke)
    // over DllImport for better AOT compatibility and performance.
    [LibraryImport("user32.dll", SetLastError = true)]
    [return: MarshalAs(UnmanagedType.Bool)]
    private static partial bool ShowWindow(IntPtr hWnd, int nCmdShow);

    [LibraryImport("ole32.dll")]
    private static partial int CoInitializeEx(IntPtr pvReserved, uint dwCoInit);
}

